module top_module(clk, load, in, shift, out);input clk, load, shift;
    input [3:0] in;
    output [3:0] out;
    reg [3:0] shadow_reg;

    always @(posedge clk) begin
        if (load) begin
            shadow_reg <= in;
        end else if (shift) begin
            shadow_reg <= {shadow_reg[2:0], 1'b0};
        end
    end

    assign out = shadow_reg;
endmodule
